import Cookies from 'js-cookie';

/**
* Cross Domain IFrame Server
*
* @class Server
* @constructor
*/
const METHODS = {
  'get': true,
  'set': true,
  'remove': true,
  'status': true
};
export default class Server {
  /**
   * @param  {Object} A key/value list of domains to allow messages to/from
   */
  constructor(whitelist) {
    if (!whitelist) {
      throw new Error('SSO server constructor requires a whitelist');
    }
    this.whitelist = whitelist;
    /* istanbul ignore if */
    if (window.parent !== window) {
      window.addEventListener("message", this.handleRequest.bind(this), false);
    }
    window.parent.postMessage(JSON.stringify({ loaded: true }), '*');
  }

  handleRequest(e) {
    /**
     * Handles the request from the client and interfaces with cookies
     * calls postMessage on the source window
     *
     * @param  {Object} e the event object from window.postMessage
     *
     */
    var eventData = this.parseData(e.data);
    var response = {
      id: eventData.id
    };
    var methodName = eventData.method ?
      String.prototype.toLowerCase.call(eventData.method) :
      '';
    if (this.isAllowed(e.origin) && METHODS[methodName]) {
      try {
        response.data = this[methodName](eventData.data);
      } catch (err) {
        response.data = { error: err.message };
      }
    } else {
      response.data = this.isAllowed(e.origin) ?
        { error: 'SSO Bad Request' } :
        { error: 'SSO Not Allowed' } ;
    }
    e.source.postMessage(JSON.stringify(response), e.origin);
  }

  get(key) {
    if (!!key && typeof key === 'string') {
      return Cookies.getJSON(key) || null;
    } else if (key instanceof Array) {
      return key.reduce((val, item) => {
        let result = this.get(item);
        if (result !== null) {
          val[item] = this.get(item);
        }
        return val;
      }, {});
    } else {
      throw Error("get argument must be a string, or array of strings");
    }
  }

  set(data) {
    if (typeof data === 'object' && !(data instanceof Array) && !!data) {
      for (let key in data) {
        Cookies.set(key, data[key], { sameSite: 'none', secure: true });
      }
      return { success: true };
    } else {
      throw Error("set argument must be an object");
    }
  }

  remove(key) {
    if (!!key && typeof key === 'string') {
      Cookies.remove(key);
    } else if (key instanceof Array) {
      key.forEach((item) => {
        this.remove(item);
      });
    } else {
      throw Error("remove argument must be a string");
    }
    return { success: true };
  }

  status() {
    return { loaded: true };
  }

  parseData(data) {
    var result;
    if (typeof data === 'string') {
      try {
        result = JSON.parse(data);
      } catch (err) {
        result = {};
      }
    } else {
      result = data || {};
    }
    return result;
  }

  // Checks the domain against the whitelist hash
  //  Expects a parsed domain array generated by @.parseUrl()
  isAllowed(url) {
    var parsed_url = this.parseUrl(url);
    // check for the existance of the whitelist key
    var rule = this.whitelist[parsed_url.domain];
    if (typeof rule !== 'undefined') {
      // if the hash value is falsey, all subdomains are allowed
      if (!rule) return true;
      // if there is no subdomain and subdomain match exists, not allowed
      if (rule && !parsed_url.subdomain) return false;

      /* istanbul ignore else */
      // check the subdomain against the subdomain rule in the whitelist
      if (rule instanceof RegExp) {
        return rule.test(parsed_url.subdomain);
      } else if (rule instanceof Array) {
        return rule.indexOf(parsed_url.subdomain) !== -1;
      } else if (typeof rule === 'string') {
        return normalizeString(rule) === normalizeString(parsed_url.subdomain);
      } else {
        return false;
      }
    } else {
      return false;
    }
  }

  parseUrl(url) {
    //regex matches only the domain without the port
    var match = url.match(/^(?:https?\:\/\/|\/?)([^\/:?#]+)(?:[\/:?#]|$)/i);
    url = match && match[1];
    //return early if regex match fails
    if (!url) return '';

    //check for subdomain and remove it if it exists
    var domain_parts = url.split('.');
    var subdomain_parts = [];
    while (domain_parts.length > 2) {
      subdomain_parts.push(domain_parts.shift());
    }

    return {
      domain: domain_parts.join('.'),
      subdomain: subdomain_parts.join('.')
    };
  }
}

function normalizeString(str) {
  return str.trim().toLowerCase();
}
